Steps:
[AUTH role=ORG_USER]
[GQL-OP setup_me]
  query { me { id contact { organizationId } } }
[GQL-EXEC setup_me]
[GQL-CAPTURE setup_me.data.me.id → USER_ID]
[GQL-CAPTURE setup_me.data.me.contact.organizationId → ORG_ID]
[GQL-OP setup_prod]
  query { products(storeId: "{{STORE_ID}}" currencyCode: "USD" first: 1 filter: "category.subtree:fc596540864a41bf8ab78734ee7353a3 price.USD:(0 TO) inStock_variations:true") { items { id } } }
[GQL-EXEC setup_prod]
[GQL-CAPTURE setup_prod.data.products.items.0.id → PRODUCT_ID]
[GQL-OP pre_clear]
  mutation { clearCart(command: { storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" }) { id } }
[GQL-EXEC pre_clear]
[GQL-OP add_item]
  mutation { addItem(command: { storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" productId: "{{PRODUCT_ID}}" quantity: 1 }) { id } }
[GQL-EXEC add_item]
[GQL-CAPTURE add_item.data.addItem.id → CART_ID]
[GQL-OP set_shipment]
  mutation {
    addOrUpdateCartShipment(command: {
      storeId: "{{STORE_ID}}" userId: "{{USER_ID}}"
      shipment: {
        shipmentMethodCode: "FixedRate" shipmentMethodOption: "Ground" price: 150
        deliveryAddress: {
          city: "New York" countryCode: "US" countryName: "United States"
          firstName: "Test" lastName: "User"
          line1: "123 Test St" postalCode: "10001"
          regionId: "NY" regionName: "New York"
        }
      }
    }) { id }
  }
[GQL-EXEC set_shipment]
[GQL-OP set_payment]
  mutation {
    addOrUpdateCartPayment(command: {
      storeId: "{{STORE_ID}}" userId: "{{USER_ID}}"
      payment: { paymentGatewayCode: "DefaultManualPaymentMethod" }
    }) { id }
  }
[GQL-EXEC set_payment]
[GQL-OP create_order]
  mutation { createOrderFromCart(command: { cartId: "{{CART_ID}}" }) { id number status organizationId } }
[GQL-EXEC create_order]

[AUTH role=ORG_USER]
[GQL-OP setup_me]
  query { me { id } }
[GQL-EXEC setup_me]
[GQL-CAPTURE setup_me.data.me.id → USER_ID]
[GQL-OP setup_prods]
  query { products(storeId: "{{STORE_ID}}" currencyCode: "USD" first: 2 filter: "category.subtree:fc596540864a41bf8ab78734ee7353a3 price.USD:(0 TO) inStock_variations:true") { items { id } } }
[GQL-EXEC setup_prods]
[GQL-CAPTURE setup_prods.data.products.items.0.id → PRODUCT_1]
[GQL-CAPTURE setup_prods.data.products.items.1.id → PRODUCT_2]
[GQL-OP pre_clear]
  mutation { clearCart(command: { storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" }) { id } }
[GQL-EXEC pre_clear]
[GQL-OP add_first]
  mutation { addItem(command: { storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" productId: "{{PRODUCT_1}}" quantity: 1 }) { id items { id } } }
[GQL-EXEC add_first]
[GQL-CAPTURE add_first.data.addItem.items.0.id → LINE_ITEM_1]
[GQL-OP add_second]
  mutation { addItem(command: { storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" productId: "{{PRODUCT_2}}" quantity: 1 }) { id items { id selectedForCheckout } } }
[GQL-EXEC add_second]
[GQL-OP unselect_one]
  mutation {
    unSelectCartItems(command: {
      storeId: "{{STORE_ID}}" userId: "{{USER_ID}}"
      lineItemIds: ["{{LINE_ITEM_1}}"]
    }) {
      id itemsCount items { id selectedForCheckout }
    }
  }
[GQL-EXEC unselect_one]
[GQL-OP cleanup_clear]
  mutation { clearCart(command: { storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" }) { id } }
[GQL-EXEC cleanup_clear]

